`,paraId:19,tocIndex:7},{value:"\u660E\u660E 3 \u884C\u4EE3\u7801\u5373\u53EF\u8F7B\u677E\u5B9E\u73B0\uFF0CPromise \u4E3A\u4F55\u8FD8\u8981\u52A0\u585E ",paraId:20},{value:"withResolvers()",paraId:20},{value:" \u65B0\u65B9\u6CD5\uFF1F",paraId:20},{value:"\u73B0\u5728\u6709\u4E9B\u5E94\u7528\u8D8A\u5199\u8D8A\u590D\u6742\uFF0C\u5076\u5C14\u4F1A\u9047\u5230\u5DE8\u5927\u7684\u539F\u5B50 Promise \u8981\u5199\u3002\u4F60\u53EF\u4EE5\u9009\u62E9\u5728 ",paraId:21,tocIndex:8},{value:"(resolve, reject) => {}",paraId:21,tocIndex:8},{value:" \u91CC\u9762\u5199 500 \u884C\u7684\u5B9E\u73B0\uFF0C\u4F46\u4F60\u6700\u597D\u628A\u8FD9 500 \u884C\u5206\u89E3\u6210\u82E5\u5E72\u4E2A\u51FD\u6570\uFF0C\u751A\u81F3\u5C01\u88C5\u6210\u4E00\u4E2A\u7C7B\u3002",paraId:21,tocIndex:8},{value:"\u5982\u679C\u4F60\u5DF2\u7ECF\u8981\u628A ",paraId:22,tocIndex:8},{value:"resolve",paraId:22,tocIndex:8},{value:" \u548C ",paraId:22,tocIndex:8},{value:"reject",paraId:22,tocIndex:8},{value:" \u5728\u591A\u4E2A\u51FD\u6570\u4E2D\u4F20\u6765\u4F20\u53BB\uFF0C\u4E00\u5F00\u59CB\u628A\u5B83\u4EEC\u653E\u5728\u4E00\u4E2A\u533F\u540D\u51FD\u6570\u91CC\u6709\u4EC0\u4E48\u610F\u601D\u5462\uFF1F\u8FD8\u4E0D\u5982\u653E\u51FA\u6765\uFF0C\u751A\u81F3\u662F\u4FDD\u5B58\u4E3A\u7C7B\u6210\u5458\uFF0C\u7B49\u5F85\u6B63\u786E\u7684\u65F6\u673A\u518D\u8C03\u7528\u5176\u4E2D\u4E00\u4E2A\u3002\u8FD9\u65F6\u5019\u4F60\u53EF\u4EE5\u81EA\u5DF1\u5B9E\u73B0 ",paraId:22,tocIndex:8},{value:"withResolvers",paraId:22,tocIndex:8},{value:"\uFF0C\u6216\u8005\u662F\u7528 API\u3002\u7528 API \u4F7F\u5F97\u6240\u6709\u4EBA\u7684\u4EE3\u7801\u66F4\u7EDF\u4E00\u3002",paraId:22,tocIndex:8},{value:"Promise.then()",paraId:20},{value:`// \u4EE5\u4E0B\u4EE3\u7801\u6BCF\u4E00\u6B65\u662F\u600E\u4E48\u6267\u884C\u7684\uFF1F\u4E3A\u4EC0\u4E48\u8F93\u51FA\u7684\u7ED3\u679C\u662F 1 3 2 4 ?

Promise.resolve()
    .then(() => console.log(1))
    .then(() => console.log(2))

Promise.resolve()
