// \u6253\u5370 2\uFF0C\u6253\u5370 4

queueMicrotask(() => { // 1
  console.log(1)
  queueMicrotask(() => { // 2
    console.log(2)
  })
})

queueMicrotask(() => { // 3
  console.log(3)
  queueMicrotask(() => { // 4
    console.log(4)
  })
})
