`,paraId:29,tocIndex:10},{value:"\u8FD9\u662F\u56E0\u4E3A Promises/A+ \u89C4\u8303\u8DDF ES2015 Promises \u4E0D\u5B8C\u5168\u7B49\u4EF7\u3002",paraId:30,tocIndex:10},{value:"ECMA262 Promise \u6784\u9020\u51FD\u6570",paraId:31,tocIndex:10},{value:"\u4E2D\uFF0C\u6CE8\u610F\u4E8B\u9879\u91CC\u63D0\u5230\uFF1A",paraId:31,tocIndex:10},{value:"The argument passed to the resolve function\xA0represents\xA0the eventual value of the deferred action and can be either the actual\xA0fulfillment\xA0value or another Promise object which will provide the value if it is fulfilled.",paraId:32,tocIndex:10},{value:"\u4F20\u9012\u7ED9 resolve \u51FD\u6570\u7684\u53C2\u6570\u8868\u793A\u5EF6\u8FDF\u52A8\u4F5C\u7684\u6700\u7EC8\u503C\uFF0C\u53EF\u4EE5\u662F\u5B9E\u9645\u7684\u503C\uFF0C\u4E5F\u53EF\u4EE5\u662F\u5176\u4ED6 Promise \u5BF9\u8C61\uFF0C\u5982\u679C\u662F Promise\uFF0C\u5219\u5F53\u8BE5 Promise \u5BF9\u8C61 fulfilled \u4E4B\u540E\u5C06\u5411 resolve \u51FD\u6570\u63D0\u4F9B\u6700\u7EC8\u503C\u3002",paraId:33,tocIndex:10},{value:"\u5728\u6211\u4EEC\u5B9E\u73B0\u7684 promise \u4E0A\u6DFB\u52A0\u5982\u4E0B\u5185\u5BB9\uFF0C\u53EF\u4EE5\u5B9E\u73B0\u4E0E ES2015 Promises \u7B49\u4EF7\u7684\u6548\u679C\u3002",paraId:34,tocIndex:10},{value:"\u67E5\u770B\u5168\u90E8\u6E90\u7801",paraId:35,tocIndex:10},{value:`// \u6DFB\u52A0\u5916\u90E8\u5DE5\u5177\u51FD\u6570 promiseResolveThenableJob
const promiseResolveThenableJob = resolvePromiseParam => {
  return new MyPromise(_resolve => {
    resolvePromiseParam.then(val => _resolve(val))
  })
}

// \u5BF9 constructor \u4E2D resolve \u51FD\u6570\u505A\u5982\u4E0B\u4FEE\u6539
const resolve = value => {
  const resolveGeneralValue = value => {
    // \u5982\u679C\u72B6\u6001\u5DF2\u7ECF\u6539\u53D8\uFF0C\u5219\u4E0D\u518D\u91CD\u590D\u6267\u884C resolve
    if (this.state === PENDING) {
      this.state = FULFILLED
      this.value = value
      this.fulfilledCbs.forEach(cb => cb())
    }
  }

  // resolve \u53C2\u6570\u4E3A promise \u60C5\u51B5
  if (value instanceof MyPromise) {
    promiseResolveThenableJob(value).then(
      val => {
        if (val instanceof MyPromise) resolve(val)
        // \u8D70\u8FD9\uFF0C\u4F1A\u6D88\u8017\u4E24\u6B21 then\uFF0Cresolve \u7684\u662F val\uFF0Cthis.value = val
        else resolveGeneralValue(val)
      },
      err => reject(err)
    )
  } else {
    resolveGeneralValue(value)
  }
}
