`,paraId:66,tocIndex:18},{value:"forwardRef \u7684\u505A\u6CD5\u672C\u8EAB\u6CA1\u6709\u4EC0\u4E48\u95EE\u9898, \u4F46\u662F\u6211\u4EEC\u662F\u5C06\u5B50\u7EC4\u4EF6\u7684 DOM \u76F4\u63A5\u66B4\u9732\u7ED9\u4E86\u7236\u7EC4\u4EF6:",paraId:67,tocIndex:18},{value:"\u76F4\u63A5\u66B4\u9732\u7ED9\u7236\u7EC4\u4EF6\u5E26\u6765\u7684\u95EE\u9898\u662F\u67D0\u4E9B\u60C5\u51B5\u7684\u4E0D\u53EF\u63A7",paraId:68,tocIndex:18},{value:"\u7236\u7EC4\u4EF6\u53EF\u4EE5\u62FF\u5230 DOM \u540E\u8FDB\u884C\u4EFB\u610F\u7684\u64CD\u4F5C",paraId:68,tocIndex:18},{value:"\u6211\u4EEC\u53EA\u662F\u5E0C\u671B\u7236\u7EC4\u4EF6\u53EF\u4EE5\u64CD\u4F5C\u7684 focus\uFF0C\u5176\u4ED6\u5E76\u4E0D\u5E0C\u671B\u5B83\u968F\u610F\u64CD\u4F5C\u5176\u4ED6\u65B9\u6CD5",paraId:68,tocIndex:18},{value:`// useImperativeHandle(ref, createHandle, [deps])
import { useRef, forwardRef, useImperativeHandle } from 'react'

const JMInput = forwardRef((props, ref) => {
  const inputRef = useRef()
  // \u4F5C\u7528: \u51CF\u5C11\u7236\u7EC4\u4EF6\u83B7\u53D6\u7684 DOM \u5143\u7D20\u5C5E\u6027, \u53EA\u66B4\u9732\u7ED9\u7236\u7EC4\u4EF6\u9700\u8981\u7528\u5230\u7684 DOM \u65B9\u6CD5
  // \u53C2\u6570 1: \u7236\u7EC4\u4EF6\u4F20\u9012\u7684 ref \u5C5E\u6027
  // \u53C2\u6570 2: \u8FD4\u56DE\u4E00\u4E2A\u5BF9\u8C61\uFF0C\u7236\u7EC4\u4EF6\u901A\u8FC7 ref.current \u8C03\u7528\u5BF9\u8C61\u4E2D\u65B9\u6CD5
  useImperativeHandle(ref, () => ({
    focus: () => {
      inputRef.current.focus()
    }
  }))
  return <input type="text" ref={inputRef} />
})

export default function ImperativeHandleDemo() {
  // \u4E3A\u4EC0\u4E48\u4F7F\u7528: \u56E0\u4E3A\u4F7F\u7528 forward + useRef \u83B7\u53D6\u5B50\u51FD\u6570\u5F0F\u7EC4\u4EF6 DOM \u65F6\uFF0C\u83B7\u53D6\u5230\u7684 dom \u5C5E\u6027\u66B4\u9732\u7684\u592A\u591A\u4E86
  // \u89E3\u51B3: \u5728\u5B50\u51FD\u6570\u5F0F\u7EC4\u4EF6\u4E2D\u5B9A\u4E49\u7236\u7EC4\u4EF6\u9700\u8981\u8FDB\u884C DOM \u64CD\u4F5C\uFF0C\u51CF\u5C11\u83B7\u53D6 DOM \u66B4\u9732\u7684\u5C5E\u6027\u8FC7\u591A
  const inputRef = useRef()

  return (
    <div>
      <button onClick={() => inputRef.current.focus()}>\u805A\u7126</button>
      <JMInput ref={inputRef} />
    </div>
  )
}
