declare function bar<const T>(x: T): T
bar('hello') // function bar<"hello">(x: "hello"): "hello"
bar([1, 2, 3]) // function bar<readonly [1, 2, 3]>(x: readonly [1, 2, 3]): readonly [1, 2, 3]
bar({name: 'chu', birthday: [2000, 1, 1]}) // ...

