      ignoreHeight: false, // \u7981\u7528\u9875\u9762\u5185\u5BB9\u7684\u9AD8\u5EA6\u9650\u5236
      ignoreFonts: false, // \u7981\u7528\u5B57\u4F53\u4E0B\u8F7D\u548C\u5E94\u7528
      breakPages: true, // \u5728\u5206\u9875\u7B26\u4E0A\u542F\u7528\u5206\u9875
